def respected_boundary(policy, audience, used_level):
    allowed = policy[audience]
    return used_level <= allowed

def pass_rate(policy, scenarios):
    if not scenarios:
        return 0.0
    ok = sum(1 for a, u in scenarios if respected_boundary(policy, a, u))
    return ok / len(scenarios)

def audit(policy, scenarios):
    return {
        "pass_rate": round(pass_rate(policy, scenarios), 2),
        "respected": sum(1 for a, u in scenarios if respected_boundary(policy, a, u)),
        "total": len(scenarios),
    }

def respected_boundary(policy, audience, used_level):
    return used_level <= policy[audience]

def pass_rate(policy, scenarios):
    ok = sum(respected_boundary(policy, a, u) for a, u in scenarios)
    return ok / len(scenarios) if scenarios else 0.0

def audit(policy, scenarios):
    ok = sum(respected_boundary(policy, a, u) for a, u in scenarios)
    rate = ok / len(scenarios) if scenarios else 0.0
    return {"pass_rate": round(rate, 2), "respected": ok, "total": len(scenarios)}
